@namespace Lumeo
@implements IAsyncDisposable
@inject Lumeo.Services.IComponentInteropService Interop

@{
    var context = new TooltipContext(_isOpen, _wrapperId, _contentId);
}

@* aria-describedby links the trigger region to the role=tooltip content so
   screen readers announce it — the tooltip's whole a11y purpose. @onfocusin /
   @onfocusout bubble from the focusable child (e.g. a Button), giving keyboard
   parity with hover; Escape dismisses per the WAI-ARIA tooltip pattern. *@
<div id="@_wrapperId" class="@Cx.Merge("relative inline-flex", Class)"
     aria-describedby="@(_isOpen ? _contentId : null)"
     @onmouseenter="HandleMouseEnter"
     @onmouseleave="HandleMouseLeave"
     @onfocusin="HandleFocusIn"
     @onfocusout="HandleFocusOut"
     @onkeydown="HandleKeyDown"
     @onpointerdown="HandlePointerDown"
     @onclick="HandleTap"
     @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int ShowDelay { get; set; } = 200;
    [Parameter] public int HideDelay { get; set; } = 0;

    /// <summary>
    /// Extra classes for the tooltip's wrapper element (the <c>relative inline-flex</c>
    /// box around the trigger). Merged via <see cref="Cx.Merge"/> so a consumer class
    /// wins conflicts without <c>!important</c> — e.g. <c>Class="w-full"</c> makes the
    /// wrapper fill its parent so a full-width trigger (e.g. a sidebar nav button) is
    /// not shrunk to content width.
    /// </summary>
    [Parameter] public string? Class { get; set; }

    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _wrapperId = LumeoIds.New("tooltip-wrapper");
    // Stable content id shared with TooltipContent so the trigger's
    // aria-describedby can reference it.
    private readonly string _contentId = LumeoIds.New("tooltip-content");
    private bool _hovered;
    private bool _focused;
    // rc.44 — on touch devices a tap "pins" the tooltip open until the next
    // tap elsewhere (registerClickOutside also now listens for touchstart, so
    // dismissal works equally on mobile).
    private bool _pinned;
    private bool _clickOutsideRegistered;
    private readonly DelayedDispatch _dispatch = new();

    private bool _isOpen => _hovered || _pinned || _focused;

    private void HandleMouseEnter()
    {
        _dispatch.Cancel();
        if (ShowDelay <= 0)
        {
            _hovered = true;
            StateHasChanged();
        }
        else
        {
            _dispatch.Schedule(ShowDelay, () => InvokeAsync(() =>
            {
                _hovered = true;
                StateHasChanged();
                return Task.CompletedTask;
            }));
        }
    }

    private void HandleMouseLeave()
    {
        _dispatch.Cancel();
        if (HideDelay <= 0)
        {
            _hovered = false;
            StateHasChanged();
        }
        else
        {
            _dispatch.Schedule(HideDelay, () => InvokeAsync(() =>
            {
                _hovered = false;
                StateHasChanged();
                return Task.CompletedTask;
            }));
        }
    }

    // Keyboard parity: focusing the trigger (or any focusable child) shows the
    // tooltip immediately; blur hides it. Radix opens HoverCard/Tooltip on
    // keyboard focus so keyboard-only users can read it.
    //
    // Gated on :focus-visible (via IsActiveElementFocusVisible), not plain focus: a mouse
    // click ALSO fires focusin (a native <button> keeps DOM focus after a click, and
    // nothing clears it), so opening unconditionally here meant the tooltip stayed open
    // after a click + moving the mouse away, until focus happened to move elsewhere for an
    // unrelated reason — reported production bug, reproducible on any clickable
    // Tooltip-wrapped element. :focus-visible is false for that click-driven focus in
    // supporting browsers, true for real keyboard navigation, so this distinguishes the
    // two without any manual pointer-type bookkeeping.
    private async Task HandleFocusIn()
    {
        _dispatch.Cancel();
        var visible = await Interop.IsActiveElementFocusVisible();
        if (!visible) return;
        _focused = true;
        StateHasChanged();
    }

    private void HandleFocusOut()
    {
        _focused = false;
        StateHasChanged();
    }

    // Escape dismisses the tooltip (clears hover + focus state) per WAI-ARIA.
    private void HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape")
        {
            // Clear the pinned (tap-to-stick) state too, otherwise Escape leaves a
            // pinned tooltip open.
            _dispatch.Cancel();
            _pinned = false;
            _hovered = false;
            _focused = false;
            StateHasChanged();
        }
    }

    // The click's input modality, recorded from the preceding pointerdown ("mouse",
    // "touch", "pen"). Null when the click had no pointerdown at all — i.e. keyboard
    // activation (Enter/Space fire a click without any pointer event).
    private string? _lastPointerType;

    private void HandlePointerDown(PointerEventArgs e) => _lastPointerType = e.PointerType;

    // TOUCH tap toggles the pinned state (rc.44): a touch device has no hover, so the
    // first tap pins the tooltip open and a second tap (or a tap elsewhere, via
    // registerClickOutside) dismisses it.
    //
    // Any OTHER activation — mouse, pen, keyboard — CLOSES the tooltip instead (Radix
    // parity: clicking a tooltip trigger dismisses its tooltip; the user has acted, the
    // hint has served its purpose). This used to pin on EVERY click: a desktop mouse
    // click flipped _pinned=true, so the tooltip stuck open even after the pointer left
    // (mouseleave only clears _hovered — _pinned kept _isOpen true) until a click landed
    // somewhere else. Reported in production on the sidebar-toggle button, reproducible
    // on every Tooltip-wrapped clickable element; nothing a consumer could do about it,
    // since no synthetic event can clear the internal state (and the 4.0.4 focus-visible
    // fix only covered the FOCUS path, not this pin/hover path). Clearing _hovered here
    // also means a cursor RESTING on the trigger after the click keeps the tooltip
    // closed until it actually leaves and re-enters — mouseenter only fires on a real
    // re-entry, so no reopen loop.
    private async Task HandleTap()
    {
        var isTouch = _lastPointerType == "touch";
        _lastPointerType = null;

        if (isTouch)
        {
            _pinned = !_pinned;
            if (_pinned && !_clickOutsideRegistered)
            {
                await Interop.RegisterClickOutside(_wrapperId, null, OnClickOutside);
                _clickOutsideRegistered = true;
            }
        }
        else
        {
            _dispatch.Cancel();
            _pinned = false;
            _hovered = false;
            _focused = false;
        }
        StateHasChanged();
    }

    private Task OnClickOutside()
    {
        if (_pinned)
        {
            _pinned = false;
            _hovered = false;
            StateHasChanged();
        }
        return Task.CompletedTask;
    }

    public async ValueTask DisposeAsync()
    {
        _dispatch.Dispose();
        if (_clickOutsideRegistered)
        {
            try { await Interop.UnregisterClickOutside(_wrapperId); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
            _clickOutsideRegistered = false;
        }
    }

    public record TooltipContext(bool IsOpen, string WrapperId, string ContentId);
}

@namespace Lumeo
@implements IAsyncDisposable
@implements IOverlayExitCallback

@*  rc.45 — fixed-position rendering + collision flip.
    Previously the tooltip was an absolutely positioned child of the trigger
    wrapper, anchored with Tailwind classes (`bottom-full start-1/2 ...`).
    That meant a tooltip near the viewport edge clipped against it.
    We now mirror the Popover pattern: render with `position: fixed`, hand
    placement off to `ComponentInteropService.PositionFixed` (floating-ui
    under the hood), which auto-flips to the opposite side when collision
    space is tight. Side is still consumer-controlled as a preference. *@
@if (_exit.Present(IsOpen))
{
    <div id="@_contentId" role="tooltip" data-state="@(IsOpen ? "open" : "closed")" data-side="@EffectiveSide" data-align="@AlignStr" class="@CssClass" inert="@ExitInert" @attributes="AdditionalAttributes">
        @ChildContent
        @if (ShowArrow)
        {
            <div class="@ArrowClasses" style="@ArrowStyle"></div>
        }
    </div>
}

@inject Lumeo.Services.IComponentInteropService Interop

@code {
    [CascadingParameter] public Tooltip.TooltipContext? Context { get; set; }

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public Lumeo.Side Side { get; set; } = Lumeo.Side.Top;
    [Parameter] public Lumeo.Align Align { get; set; } = Lumeo.Align.Center;
    [Parameter] public bool ShowArrow { get; set; } = true;
    [Parameter] public int Offset { get; set; } = 8;
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Use the content id from the Tooltip parent so the trigger's
    // aria-describedby points at this role=tooltip element.
    private string _contentId => Context?.ContentId ?? string.Empty;
    private bool _registered;

    // B11 exit latch (shared infra). Enter keeps fade-in; exit uses zoom-out
    // (scale-down + fade) to match shadcn/Radix tooltip's
    // data-[state=closed]:zoom-out-95 + fade-out.
    private readonly OverlayExitAnimator _exit = new();
    private DotNetObjectReference<TooltipContent>? _selfRef;
    private const int ExitDurationMs = 250;

    // Last placement values actually handed to PositionFixed. A live Side/Offset/Align
    // change while the tooltip is open must re-run PositionFixed so the box moves;
    // storing the applied values stops a same-value re-render from thrashing JS.
    private string? _appliedSide;
    private int? _appliedOffset;
    private string? _appliedAlign;

    // The side the box ACTUALLY resolved to, echoed back by PositionFixed after any collision flip.
    // Null until the first placement; the arrow + data-side render from EffectiveSide so they follow a flip.
    private string? _resolvedSide;

    private bool IsOpen => Context?.IsOpen ?? false;

    private string CssClass => Cx.Merge(
        "fixed z-50 overflow-visible rounded-md bg-primary px-3 py-1.5 text-xs text-primary-foreground",
        AnimationClasses,
        Class);

    // pointer-events-none during the exit window keeps the fading tooltip inert
    // (mouseenter on the exiting box can't affect state) — parity with the menu
    // surfaces and the Radix pointer-events-none tooltip contract (P2).
    private string AnimationClasses => IsOpen
        ? "opacity-100 visible animate-fade-in"
        : (_exit.Exiting ? "opacity-100 visible animate-zoom-out pointer-events-none" : "opacity-0 invisible");

    // `inert` during the exit window keeps the closing tooltip out of the tab order +
    // a11y tree — parity with the menu/nav surfaces (round-2 P2). A tooltip should hold
    // no focusable content per WAI-ARIA, so this is defence-in-depth.
    private string? ExitInert => _exit.Exiting ? "true" : null;

    private string SideStr => Side switch
    {
        Lumeo.Side.Top => "top",
        Lumeo.Side.Bottom => "bottom",
        Lumeo.Side.Left => "left",
        Lumeo.Side.Right => "right",
        _ => "top"
    };

    private string AlignStr => Align switch
    {
        Lumeo.Align.Start => "start",
        Lumeo.Align.End => "end",
        _ => "center"
    };

    // The side the arrow + data-side actually render from: the resolved side once positionFixed has run
    // (so a collision flip re-points the arrow), falling back to the requested SideStr before placement.
    private string EffectiveSide => _resolvedSide ?? SideStr;

    // Rotated square — same visual as Popover/HoverCard but no border (tooltip is a solid primary surface).
    // Derived from EffectiveSide (the SAME value rendered as data-side) so the arrow edge and the data-side
    // attribute always agree — including after a positionFixed COLLISION FLIP, which echoes the resolved
    // side back to _resolvedSide.
    private string ArrowClasses => EffectiveSide switch
    {
        "top" => "absolute top-full -translate-x-1/2 -translate-y-1/2 rotate-45 h-2 w-2 bg-primary",
        "bottom" => "absolute bottom-full -translate-x-1/2 translate-y-1/2 rotate-45 h-2 w-2 bg-primary",
        "left" => "absolute left-full -translate-y-1/2 -translate-x-1/2 rotate-45 h-2 w-2 bg-primary",
        "right" => "absolute right-full -translate-y-1/2 translate-x-1/2 rotate-45 h-2 w-2 bg-primary",
        _ => "absolute top-full -translate-x-1/2 -translate-y-1/2 rotate-45 h-2 w-2 bg-primary"
    };

    // Anchors the arrow to where the TRIGGER's center falls within the box, not the box's own
    // center: positionFixed writes --lumeo-arrow-x/y (viewport-collision-aware, the floating-ui
    // "arrow middleware" equivalent) onto the content element on every reposition; the 50%
    // fallback preserves the classic box-centered arrow until the first placement runs (and in
    // bUnit, where no JS executes). Previously this was a hardcoded left-1/2 / top-1/2, so a
    // box shifted by the viewport-edge clamp (trigger near the screen edge) kept its arrow at
    // the box center, pointing into empty space instead of at the trigger (user-reported,
    // screenshot-confirmed: box center ~27px off the trigger center, arrow still box-centered).
    // The offset is PHYSICAL (left/top, not logical inset-inline-start): the box is positioned
    // by JS in LTR viewport coordinates and the translate is physical too, so this stays
    // correct under RTL (same reasoning as the former physical left-1/2, Codex P2).
    private string ArrowStyle => EffectiveSide switch
    {
        "left" or "right" => "top: var(--lumeo-arrow-y, 50%)",
        _ => "left: var(--lumeo-arrow-x, 50%)"
    };

    protected override void OnParametersSet()
        => _exit.OnParameters(IsOpen, ExitDurationMs, () => InvokeAsync(FinishExit));

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Re-position when first opening OR when Side/Offset changed while already
        // open. The old `!_registered` one-shot latch ignored live placement changes,
        // leaving the box at its original spot. positionFixed cleans up the prior
        // placement (keyed by contentId) at entry, so re-calling it is safe.
        if (IsOpen && Context is not null
            && (!_registered || _appliedSide != SideStr || _appliedOffset != Offset || _appliedAlign != AlignStr))
        {
            // OnLiveSideChanged covers a LATER flip too — a scroll/resize reposition while this tooltip
            // stays open at the same Side/Offset/Align (Codex P2, round-11/14). The guard above keys off
            // SideStr/Offset/AlignStr (NOT _resolvedSide), so OnLiveSideChanged's StateHasChanged does
            // not re-enter this branch — no render loop, no re-registering positionFixed.
            var resolved = await Interop.PositionFixed(_contentId, Context.WrapperId, AlignStr, false, SideStr, Offset, OnLiveSideChanged);
            _registered = true;
            _appliedSide = SideStr;
            _appliedOffset = Offset;
            _appliedAlign = AlignStr;
            // The box may have collision-flipped to the opposite side on this INITIAL placement; re-render
            // so the arrow + data-side follow it.
            if (resolved != _resolvedSide)
            {
                _resolvedSide = resolved;
                StateHasChanged();
            }
        }
        else if (!IsOpen && _registered)
        {
            // Cleanup (unpositionFixed) runs immediately on close: it stops the
            // reposition rAF and leaves the inline top/left so the box freezes in
            // place while the zoom-out plays. The element stays mounted for the exit
            // via the _exit.Present gate.
            await Cleanup();
        }

        await _exit.WireExitAsync(async () =>
        {
            _selfRef ??= DotNetObjectReference.Create(this);
            try { await Interop.AttachOverlayExitEnd(_contentId, _selfRef); }
            catch (Microsoft.JSInterop.JSDisconnectedException) { }
        });
    }

    [JSInvokable]
    public Task OnExitAnimationEnd() => InvokeAsync(FinishExit);

    private void FinishExit()
    {
        if (_exit.Finish())
        {
            // Exit is over and the box unmounts now: drop the resolved side AFTER the
            // exit window (not in Cleanup) so a fresh open re-derives it from scratch.
            // Retaining it through the exit kept the frozen box's arrow + data-side on
            // the collision-flipped edge instead of snapping back to the unflipped
            // requested Side mid-fade (minor desync, Codex/CodeRabbit).
            _resolvedSide = null;
            StateHasChanged();
        }
    }

    private Task OnLiveSideChanged(string side)
    {
        if (side == _resolvedSide) return Task.CompletedTask;
        _resolvedSide = side;
        StateHasChanged();
        return Task.CompletedTask;
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(_contentId); }
        catch (Microsoft.JSInterop.JSDisconnectedException) { }
        _registered = false;
        _appliedSide = null;
        _appliedOffset = null;
        _appliedAlign = null;
        // NOTE: _resolvedSide is intentionally NOT cleared here. Cleanup runs
        // immediately on close, but the box stays mounted (frozen) for the exit
        // window — keeping the resolved (possibly collision-flipped) side means the
        // arrow + data-side stay put through the fade. It is cleared in FinishExit
        // once the box actually unmounts.
    }

    public async ValueTask DisposeAsync()
    {
        _exit.Dispose();
        _selfRef?.Dispose();
        if (_registered) await Cleanup();
    }

}

@namespace Lumeo

@if (AsChild)
{
    @* asChild: render NO wrapper. Cascade the slot so a cooperating child (a Lumeo
       <Button>, or a manual <ChildContentSlot> splat) becomes the single trigger
       element. Tooltip's open/close behaviour lives on the Tooltip ROOT wrapper and
       is driven by bubbled mouseenter/focusin, so the slot carries NO handlers — its
       sole job is to put aria-describedby on the actual focusable element. An ancestor
       <div> can't describe the inner button, so without asChild a screen reader never
       announces the tooltip on focus; folding it onto the child fixes that. *@
    <CascadingValue Value="Slot" IsFixed="false">
        @if (ChildContentSlot is not null)
        {
            @ChildContentSlot(Slot)
        }
        else
        {
            @ChildContent
        }
    </CascadingValue>
}
else
{
    <div class="@CssClass" data-state="@(Context.IsOpen ? "open" : "closed")" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}

@code {
    [CascadingParameter] public Tooltip.TooltipContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }

    /// <summary>
    /// Tier-2 escape hatch for <see cref="AsChild"/> with arbitrary (non-Lumeo) markup:
    /// receives the <see cref="TriggerSlot"/> so the consumer can splat
    /// <c>@attributes="slot.Attributes"</c> onto their own single element (which adds
    /// the <c>aria-describedby</c> when the tooltip is open). Lumeo <c>&lt;Button&gt;</c>
    /// children need only <see cref="AsChild"/> — they consume the slot automatically.
    /// </summary>
    [Parameter] public RenderFragment<TriggerSlot>? ChildContentSlot { get; set; }

    /// <summary>
    /// When <c>true</c>, the trigger renders NO wrapper element and instead cascades a
    /// <see cref="TriggerSlot"/> that a cooperating child folds onto its own single root
    /// element. The key effect is correct a11y: <c>aria-describedby</c> lands on the
    /// real focusable control (so a screen reader announces the tooltip on focus) rather
    /// than on a non-focusable wrapper <c>&lt;div&gt;</c>. Hover/focus open-close still
    /// works via the events bubbling to the Tooltip root. Default <c>false</c> preserves
    /// the current <c>inline-flex</c> wrapper exactly.
    /// </summary>
    [Parameter] public bool AsChild { get; set; }

    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("inline-flex", Class);

    private TriggerSlot Slot => new(
        Id: null,                                 // Tooltip anchors positioning on its root wrapper, not the trigger
        Class: Cx.Merge("inline-flex", Class),
        Attributes: BuildAttrs(),
        OnClick: default);                        // behaviour bubbles to the Tooltip root; no handler on the child

    private IReadOnlyDictionary<string, object> BuildAttrs()
    {
        var d = new Dictionary<string, object>
        {
            ["data-state"] = Context.IsOpen ? "open" : "closed",
        };
        // aria-describedby must reference the role=tooltip content from the FOCUSABLE
        // element so the screen reader announces it on focus (only while open — the
        // content isn't in the DOM when closed).
        if (Context.IsOpen) d["aria-describedby"] = Context.ContentId;
        if (AdditionalAttributes is not null)
            foreach (var kv in AdditionalAttributes) d[kv.Key] = kv.Value; // author wins on collision
        return d;
    }
}
